class LmdbScalarSubqueryCorrelationExecutionTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final IRI ROW = VF.createIRI("urn:test:row");
	private static final IRI TAG = VF.createIRI("urn:test:tag");
	private static final IRI FLAG = VF.createIRI("urn:test:flag");

	@AfterEach
	void clearPlannerFlags() {
		System.clearProperty(LmdbHypergraphJoinPlanner.DPHYP_PROPERTY);
		System.clearProperty(LmdbJoinIslandConnectivity.OPAQUE_FACTORS_PROPERTY);
	}

	@Test
	void sameNameScalarReferenceUsesOnlyBindingsVisibleAtItsOccurrence(@TempDir File dataDir) {
		System.setProperty(LmdbHypergraphJoinPlanner.DPHYP_PROPERTY, "true");
		System.setProperty(LmdbJoinIslandConnectivity.OPAQUE_FACTORS_PROPERTY, "true");
		LmdbStore store = new LmdbStore(dataDir, new LmdbStoreConfig("spoc,ospc,psoc"));
		store.init();
		try {
			loadData(store);
			for (boolean wrapped : new boolean[] { false, true }) {
				assertEquals(Set.of("bad", "good"), evaluateTags(store, query(true, wrapped)),
						"A producer occurring later must not retroactively correlate an earlier scalar subquery");
				assertEquals(Set.of("good"), evaluateTags(store, query(false, wrapped)),
						"A producer occurring earlier must remain visible to the later scalar subquery");
			}
		} finally {
			store.shutDown();
		}
	}

	private static void loadData(LmdbStore store) {
		try (SailConnection connection = store.getConnection()) {
			connection.begin();
			connection.addStatement(VF.createIRI("urn:test:entity"), ROW, VF.createLiteral("row"));
			connection.addStatement(VF.createIRI("urn:test:good"), TAG, VF.createLiteral("good"));
			connection.addStatement(VF.createIRI("urn:test:bad"), TAG, VF.createLiteral("bad"));
			connection.addStatement(VF.createIRI("urn:test:good"), FLAG, VF.createLiteral(true));
			connection.commit();
		}
	}

	private static TupleExpr query(boolean scalarFirst, boolean wrapped) {
		StatementPattern stream = new StatementPattern(new Var("entity"), new Var("rowPredicate", ROW),
				new Var("value"));
		StatementPattern scalar = new StatementPattern(new Var("probe"), new Var("flagPredicate", FLAG),
				new Var("flagValue", VF.createLiteral(true)));
		ValueExpr exists = new Exists(scalar);
		if (wrapped) {
			exists = new And(exists, new ValueConstant(VF.createLiteral(true)));
		}
		Filter filter = new Filter(stream, exists);
		StatementPattern producer = new StatementPattern(new Var("probe"), new Var("tagPredicate", TAG),
				new Var("tag"));
		return new QueryRoot(scalarFirst ? new Join(filter, producer) : new Join(producer, filter));
	}

	private static Set<String> evaluateTags(LmdbStore store, TupleExpr tupleExpr) {
		Set<String> tags = new LinkedHashSet<>();
		try (SailConnection connection = store.getConnection();
				CloseableIteration<? extends BindingSet> result = connection.evaluate(tupleExpr, null,
						EmptyBindingSet.getInstance(), false)) {
			while (result.hasNext()) {
				tags.add(result.next().getValue("tag").stringValue());
			}
		}
		return tags;
	}
}
